			&lt;p style=&quot;text-align: center;&quot;&gt;Seventh&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;Union list, State list and the concurrent list&lt;/p&gt;
