	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;&lt;font color=&quot;#58595b&quot;&gt;अनुसूची&lt;/font&gt;&lt;/strong&gt;&lt;/p&gt;
